  ('social-worker-moex-01534', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Levison的觀點，在28至33歲階段有關成人前期的特質，下列何者正確？', '["職業、友誼、生活方式的初步選擇", "生活結構的改變，會產生重大壓力", "在社會上立足，家庭與職涯成就上的進展", "開始對生命意義、方向、價值的質疑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01535', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '國內的兒童虐待事件已逐漸受到民眾的關注。依據調查，最常見的虐待方式是那一種？', '["身體虐待", "疏忽", "性虐待", "情緒（心理）虐待"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01536', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '學者指出，情緒上的困擾會影響兒童對自己的感覺以及生活的環境。具有憂鬱傾向的兒童會有 「習得的無助感」，其形成的歸因主要為何？', '["失敗歸咎自己，成功是運氣佳", "失敗是運氣不佳，成功是運氣佳", "失敗是別人造成，成功是自己努力", "失敗是別人造成，成功是運氣佳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01537', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '與成年期任務相關的親密關係或工作職場，均有可能體驗到溝通方式差異所引發的憤怒與沮喪， 下列何者對溝通沒有幫助？', '["留意口語與非口語訊息的一致性", "練習傾聽", "事先假設對方的目的為何", "鼓勵表達感受"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01538', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '親密與孤立是成年早期面臨的人際議題，不能獲得親密時會感受孤立、孤單、寂寞，下列何者錯誤？', '["孤單感受可能是暫時的或和情境有關的", "寂寞意指擁有的人際關係少於自己的期望", "獨處不一定會寂寞", "有愈多朋友，愈不會寂寞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01539', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年時期認知發展對青少年行為的影響，不包含下列那一項？', '["青少年情緒的變化", "青少年喜歡冒險", "青少年很難抗拒同儕壓力", "青少年平衡感變差"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01540', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '隨著生育年齡提高，現今很多母親在超過35歲的年齡懷孕生產，高齡懷孕可能面臨的一個主要 風險是生下唐氏症的嬰兒，有關唐氏症的敘述，下列何者錯誤？', '["唐氏症是一種染色體異常的疾病", "唐氏症一般會有中重度智能不足的情形", "唐氏症很少伴隨其他的合併症", "唐氏症多能從外觀辨識"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "225c0ce9caca", "answer_pdf_sha1": "7f33815a6b91", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
